for c in range(nC):
    succ = {i: j for i in range(nN) for j in range(nN) if cE[c][i][j] == 1}
    active = set(succ)
    assert active, "each cycle must contain at least one edge"
    start = min(active)
    visited, node = [], start
    while node not in visited:
        visited.append(node)
        node = succ[node]
    assert node == start and set(visited) == active

